import base64

def confirmAuth(headers):
    token = headers.get('AuthToken')
    if not token:
        return None
    try:
        decoded = base64.b64decode(token)
    except (base64.binascii.Error, ValueError):
        return None
    try:
        token_obj = cPickle.loads(decoded)
    except (cPickle.PickleError, EOFError, AttributeError, ImportError, IndexError):
        return None
    return token_obj

